import{_ as s,o,c as e,ag as i}from"./chunks/framework.hRhVUe7m.js";const v=JSON.parse('{"title":"通道部署","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/docker-start.md","filePath":"zh/guide/docker-start.md"}'),l={name:"zh/guide/docker-start.md"};function t(d,a,r,c,n,p){return o(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="通道部署" tabindex="-1">通道部署 <a class="header-anchor" href="#通道部署" aria-label="Permalink to &quot;通道部署&quot;">​</a></h1><div class="lead-panel"><span class="kicker">生产环境部署</span><h1>将 MathClaw 部署为稳定运行的服务</h1><p>稳定部署的关键是让 gateway、console 和 workspace 分离但连通，确保外部通道、学习计划、图谱记忆和自动总结都能读写同一份数据。</p><div class="badge-list"><span>Gateway</span><span>Console</span><span>Workspace</span><span>Channels</span></div></div><div class="deployment-grid"><div class="deployment-card"><h3>Gateway 服务</h3><p>负责通道接入、AI 解答执行，以及每轮会话后的记忆更新。</p></div><div class="deployment-card"><h3>Console 服务</h3><p>提供运行状态、图谱、计划、定时任务和技能面板的管理界面。</p></div><div class="deployment-card"><h3>持久化 workspace</h3><p>保存 sessions、memory、graphs 和定时任务状态，是所有页面的数据来源。</p></div></div><h2 id="推荐部署模式" tabindex="-1">推荐部署模式 <a class="header-anchor" href="#推荐部署模式" aria-label="Permalink to &quot;推荐部署模式&quot;">​</a></h2><div class="topology-strip"><div class="topology-card"><strong>Channels</strong> 企业微信、QQ、飞书或 Web 入口将学习任务送入系统。 </div><div class="topology-card"><strong>Gateway</strong> 代理运行时负责执行，并将状态写入 workspace。 </div><div class="topology-card"><strong>Workspace</strong> 会话、记忆、图谱和定时任务状态在此持续积累。 </div><div class="topology-card"><strong>Console</strong> 管理者通过控制台查看系统状态、学习计划和图谱质量。 </div></div><div class="checklist-grid"><div class="checklist-card"><h3>运维建议</h3><ul><li>将 workspace 放在持久化存储上</li><li>gateway 和 console 作为两个长期运行服务分别启动</li><li>只启用生产环境实际需要的通道</li></ul></div><div class="checklist-card"><h3>上线后优先检查</h3><ul><li>运行状态：服务、provider、通道是否正常</li><li>定时任务：日总结和周总结是否按计划执行</li><li>记忆页：图谱数据是否正常更新</li></ul></div></div><h2 id="常见通道选择" tabindex="-1">常见通道选择 <a class="header-anchor" href="#常见通道选择" aria-label="Permalink to &quot;常见通道选择&quot;">​</a></h2><div class="callout-strip"><div class="callout-chip"><strong>企业微信</strong> 适合真实教学运营和企业环境。 </div><div class="callout-chip"><strong>QQ / 飞书</strong> 适合作为学生入口或企业协作入口。 </div><div class="callout-chip"><strong>Web Console</strong> 建议始终保留，作为管理和演示入口。 </div></div>',8)])])}const g=s(l,[["render",t]]);export{v as __pageData,g as default};
